// // This module compares two 4-bit binary numbers A and B.
// It outputs whether A is less than B (GT), greater than B (LT), or equal to B (EQ).

module magnitude_comparator (  
    input [3:0] A,  
    input [3:0] B,  
    output GT,  
    output LT,  
    output EQ  
);  
    assign GT = (A > B);  
    assign LT = (A < B);  
    assign EQ = (A == B);  
endmodule
